#!/usr/bin/env python3\n\"\"\"\nDemonstrate S1 vs S2 Cognitive Differences in Flee\n\nThis script shows how System 1 and System 2 decision-making produce\ndifferent behaviors in agent-based displacement modeling.\n\"\"\"\n\nimport sys\nimport os\nfrom pathlib import Path\n\ndef setup_environment():\n    \"\"\"Set up the environment to run Flee properly.\"\"\"\n    current_dir = Path(__file__).parent\n    if str(current_dir) not in sys.path:\n        sys.path.insert(0, str(current_dir))\n    print(f\"✅ Environment set up: {current_dir}\")\n\ndef test_cognitive_pressure_calculation():\n    \"\"\"Demonstrate cognitive pressure calculation with different scenarios.\"\"\"\n    print(\"\\n🧠 COGNITIVE PRESSURE CALCULATION DEMO\")\n    print(\"=\" * 50)\n    \n    try:\n        from flee.SimulationSettings import SimulationSettings\n        from flee.flee import Person, Location\n        \n        # Load settings\n        SimulationSettings.ReadFromYML(\"test_data/test_settings.yml\")\n        \n        # Create test scenarios\n        scenarios = [\n            {\n                \"name\": \"Peaceful Area\",\n                \"conflict_intensity\": 0.0,\n                \"connections\": 3,\n                \"time_of_conflict\": -1,\n                \"expected_pressure\": \"Very Low\"\n            },\n            {\n                \"name\": \"Low Conflict\", \n                \"conflict_intensity\": 0.3,\n                \"connections\": 3,\n                \"time_of_conflict\": 0,\n                \"expected_pressure\": \"Low\"\n            },\n            {\n                \"name\": \"High Conflict + Connected\",\n                \"conflict_intensity\": 0.8,\n                \"connections\": 8,\n                \"time_of_conflict\": 0,\n                \"expected_pressure\": \"High\"\n            },\n            {\n                \"name\": \"High Conflict + Isolated\",\n                \"conflict_intensity\": 0.8,\n                \"connections\": 1,\n                \"time_of_conflict\": 0,\n                \"expected_pressure\": \"Medium\"\n            },\n            {\n                \"name\": \"Old Conflict (Recovery)\",\n                \"conflict_intensity\": 0.8,\n                \"connections\": 5,\n                \"time_of_conflict\": -60,  # 60 days ago\n                \"expected_pressure\": \"Very Low\"\n            }\n        ]\n        \n        print(f\"{'Scenario':<25} {'Conflict':<8} {'Connections':<11} {'Pressure':<8} {'Expected':<10}\")\n        print(\"-\" * 70)\n        \n        for scenario in scenarios:\n            # Create location with conflict\n            location = Location(\"TestLoc\", 0, 0, 1000)\n            location.conflict_intensity = {1: scenario[\"conflict_intensity\"]}\n            location.time_of_conflict = scenario[\"time_of_conflict\"]\n            \n            # Create agent\n            agent = Person(location, attributes={\"connections\": scenario[\"connections\"]})\n            \n            # Calculate pressure\n            pressure = agent.calculate_cognitive_pressure(time=1)\n            \n            print(f\"{scenario['name']:<25} {scenario['conflict_intensity']:<8.1f} {scenario['connections']:<11} {pressure:<8.3f} {scenario['expected_pressure']:<10}\")\n        \n        return True\n        \n    except Exception as e:\n        print(f\"❌ Cognitive pressure test failed: {e}\")\n        import traceback\n        traceback.print_exc()\n        return False\n\ndef test_system2_capability():\n    \"\"\"Demonstrate System 2 capability determination.\"\"\"\n    print(\"\\n🎯 SYSTEM 2 CAPABILITY DEMO\")\n    print(\"=\" * 50)\n    \n    try:\n        from flee.SimulationSettings import SimulationSettings\n        from flee.flee import Person, Location\n        \n        # Load settings\n        SimulationSettings.ReadFromYML(\"test_data/test_settings.yml\")\n        \n        # Test different connection levels\n        connection_levels = [0, 1, 2, 3, 4, 5, 8, 10]\n        \n        print(f\"{'Connections':<12} {'S2 Capable':<12} {'Reason'}\")\n        print(\"-\" * 40)\n        \n        location = Location(\"TestLoc\", 0, 0, 1000)\n        \n        for connections in connection_levels:\n            agent = Person(location, attributes={\"connections\": connections})\n            s2_capable = agent.get_system2_capable()\n            \n            if s2_capable:\n                reason = \"Sufficient connections\"\n            else:\n                reason = \"Too few connections\"\n            \n            print(f\"{connections:<12} {s2_capable:<12} {reason}\")\n        \n        return True\n        \n    except Exception as e:\n        print(f\"❌ System 2 capability test failed: {e}\")\n        return False\n\ndef test_cognitive_decision_differences():\n    \"\"\"Demonstrate actual decision differences between S1 and S2.\"\"\"\n    print(\"\\n⚖️  COGNITIVE DECISION DIFFERENCES DEMO\")\n    print(\"=\" * 50)\n    \n    try:\n        from flee.SimulationSettings import SimulationSettings\n        from flee.flee import Person, Location\n        from flee import moving\n        \n        # Load settings and enable cognitive system\n        SimulationSettings.ReadFromYML(\"test_data/test_settings.yml\")\n        SimulationSettings.move_rules[\"TwoSystemDecisionMaking\"] = True\n        SimulationSettings.move_rules[\"conflict_threshold\"] = 0.3\n        \n        # Test scenarios\n        test_cases = [\n            {\n                \"name\": \"System 1 Agent (Low Connections)\",\n                \"connections\": 1,\n                \"conflict_intensity\": 0.2,\n                \"expected_system\": \"S1\"\n            },\n            {\n                \"name\": \"System 2 Agent (High Conflict + Connections)\",\n                \"connections\": 6,\n                \"conflict_intensity\": 0.8,\n                \"expected_system\": \"S2\"\n            },\n            {\n                \"name\": \"Borderline Case (Medium Everything)\",\n                \"connections\": 3,\n                \"conflict_intensity\": 0.4,\n                \"expected_system\": \"S1 or S2\"\n            }\n        ]\n        \n        print(f\"{'Test Case':<35} {'Connections':<11} {'Conflict':<8} {'Pressure':<8} {'System':<6} {'Move Chance':<10}\")\n        print(\"-\" * 85)\n        \n        for case in test_cases:\n            # Create location with conflict\n            location = Location(\"ConflictZone\", 0, 0, 1000)\n            location.conflict_intensity = {1: case[\"conflict_intensity\"]}\n            location.time_of_conflict = 0\n            \n            # Create agent\n            agent = Person(location, attributes={\"connections\": case[\"connections\"]})\n            \n            # Calculate cognitive pressure\n            pressure = agent.calculate_cognitive_pressure(time=1)\n            \n            # Test move chance calculation (this triggers cognitive switching)\n            movechance, system2_active = moving.calculateMoveChance(agent, False, 1)\n            \n            # Determine which system is active\n            if system2_active:\n                system = \"S2\"\n            else:\n                system = \"S1\"\n            \n            print(f\"{case['name']:<35} {case['connections']:<11} {case['conflict_intensity']:<8.1f} {pressure:<8.3f} {system:<6} {movechance:<10.3f}\")\n            print(f\"   Agent state: {agent.cognitive_state}, S2 activations: {agent.system2_activations}\")\n        \n        return True\n        \n    except Exception as e:\n        print(f\"❌ Cognitive decision test failed: {e}\")\n        import traceback\n        traceback.print_exc()\n        return False\n\ndef test_social_connectivity_dynamics():\n    \"\"\"Demonstrate how social connectivity changes in different environments.\"\"\"\n    print(\"\\n🤝 SOCIAL CONNECTIVITY DYNAMICS DEMO\")\n    print(\"=\" * 50)\n    \n    try:\n        from flee.SimulationSettings import SimulationSettings\n        from flee.flee import Person\n        \n        # Load settings\n        SimulationSettings.ReadFromYML(\"test_data/test_settings.yml\")\n        SimulationSettings.move_rules[\"TwoSystemDecisionMaking\"] = True\n        \n        # Create mock locations with different population densities\n        class MockLocation:\n            def __init__(self, name, numAgents):\n                self.name = name\n                self.numAgents = numAgents\n                self.camp = False\n                self.idpcamp = False\n                self.conflict = 0.0\n        \n        locations = [\n            MockLocation(\"Isolated Village\", 5),\n            MockLocation(\"Small Town\", 50),\n            MockLocation(\"City\", 500),\n            MockLocation(\"Refugee Camp\", 1000)\n        ]\n        \n        print(f\"{'Location':<15} {'Population':<10} {'Initial Conn.':<12} {'Final Conn.':<11} {'Change'}\")\n        print(\"-\" * 65)\n        \n        for location in locations:\n            # Create agent with moderate initial connections\n            agent = Person(None, attributes={\"connections\": 4})\n            initial_connections = agent.attributes[\"connections\"]\n            \n            # Update social connectivity based on location\n            agent.update_social_connectivity(location, time=0)\n            final_connections = agent.attributes[\"connections\"]\n            \n            change = final_connections - initial_connections\n            change_str = f\"+{change:.1f}\" if change > 0 else f\"{change:.1f}\"\n            \n            print(f\"{location.name:<15} {location.numAgents:<10} {initial_connections:<12} {final_connections:<11.1f} {change_str}\")\n        \n        return True\n        \n    except Exception as e:\n        print(f\"❌ Social connectivity test failed: {e}\")\n        import traceback\n        traceback.print_exc()\n        return False\n\ndef test_cognitive_state_transitions():\n    \"\"\"Demonstrate how agents transition between S1 and S2 states.\"\"\"\n    print(\"\\n🔄 COGNITIVE STATE TRANSITIONS DEMO\")\n    print(\"=\" * 50)\n    \n    try:\n        from flee.SimulationSettings import SimulationSettings\n        from flee.flee import Person, Location\n        from flee import moving\n        \n        # Load settings\n        SimulationSettings.ReadFromYML(\"test_data/test_settings.yml\")\n        SimulationSettings.move_rules[\"TwoSystemDecisionMaking\"] = True\n        SimulationSettings.move_rules[\"conflict_threshold\"] = 0.4\n        \n        # Create agent capable of System 2\n        location = Location(\"TestLocation\", 0, 0, 1000)\n        agent = Person(location, attributes={\"connections\": 5})\n        \n        # Simulate conflict escalation over time\n        conflict_levels = [0.0, 0.2, 0.5, 0.8, 0.6, 0.3, 0.1]\n        \n        print(f\"{'Time':<4} {'Conflict':<8} {'Pressure':<8} {'State':<5} {'S2 Active':<9} {'Move Chance':<10}\")\n        print(\"-\" * 55)\n        \n        for time, conflict in enumerate(conflict_levels):\n            # Update conflict intensity\n            location.conflict_intensity = {time: conflict}\n            location.time_of_conflict = 0 if conflict > 0 else -1\n            \n            # Calculate pressure and move chance\n            pressure = agent.calculate_cognitive_pressure(time=time)\n            movechance, system2_active = moving.calculateMoveChance(agent, False, time)\n            \n            print(f\"{time:<4} {conflict:<8.1f} {pressure:<8.3f} {agent.cognitive_state:<5} {system2_active:<9} {movechance:<10.3f}\")\n        \n        print(f\"\\nTotal S2 activations: {agent.system2_activations}\")\n        \n        return True\n        \n    except Exception as e:\n        print(f\"❌ Cognitive state transition test failed: {e}\")\n        import traceback\n        traceback.print_exc()\n        return False\n\ndef main():\n    \"\"\"Run all cognitive system demonstrations.\"\"\"\n    print(\"🧠 FLEE COGNITIVE SYSTEM DEMONSTRATION\")\n    print(\"=\" * 60)\n    print(\"This demo shows how System 1 and System 2 decision-making\")\n    print(\"produce different behaviors in displacement modeling.\")\n    print(\"=\" * 60)\n    \n    # Setup\n    setup_environment()\n    \n    # Run demonstrations\n    tests = [\n        (\"Cognitive Pressure Calculation\", test_cognitive_pressure_calculation),\n        (\"System 2 Capability\", test_system2_capability),\n        (\"Cognitive Decision Differences\", test_cognitive_decision_differences),\n        (\"Social Connectivity Dynamics\", test_social_connectivity_dynamics),\n        (\"Cognitive State Transitions\", test_cognitive_state_transitions)\n    ]\n    \n    results = {}\n    \n    for test_name, test_func in tests:\n        try:\n            results[test_name] = test_func()\n        except Exception as e:\n            print(f\"❌ {test_name} crashed: {e}\")\n            results[test_name] = False\n    \n    # Summary\n    print(\"\\n\" + \"=\" * 60)\n    print(\"DEMONSTRATION SUMMARY\")\n    print(\"=\" * 60)\n    \n    passed = 0\n    total = len(tests)\n    \n    for test_name, result in results.items():\n        status = \"✅ SUCCESS\" if result else \"❌ FAILED\"\n        print(f\"{test_name:<35} {status}\")\n        if result:\n            passed += 1\n    \n    print(f\"\\nOverall: {passed}/{total} demonstrations successful\")\n    \n    if passed == total:\n        print(\"\\n🎉 All demonstrations successful!\")\n        print(\"\\n📋 Key Findings:\")\n        print(\"   ✅ Cognitive pressure varies with conflict intensity and connectivity\")\n        print(\"   ✅ System 2 capability depends on social connections\")\n        print(\"   ✅ S1 and S2 produce different move chances and behaviors\")\n        print(\"   ✅ Social connectivity adapts to population density\")\n        print(\"   ✅ Agents transition between cognitive states dynamically\")\n        print(\"\\n🚀 The cognitive system is working perfectly!\")\n        return True\n    else:\n        print(\"\\n⚠️  Some demonstrations failed.\")\n        return False\n\nif __name__ == \"__main__\":\n    success = main()\n    sys.exit(0 if success else 1)\n"